const body = $json.body;
let chatId = null;
let messageId = null;
let username = null;
let firstName = null;
let lastName = null;
let isPremium = false;
let languageCode = 'en';
let searchText = null;
let businessConnectionId = null;

// Проверяем оба варианта: message или business_message
const message = body.message || body.business_message;

if (message) {
  chatId = message.chat.id;
  messageId = message.message_id;

  // ✅ Берем данные ОТПРАВИТЕЛЯ из from
  if (message.from) {
    username = message.from.username || null;
    firstName = message.from.first_name || '';
    lastName = message.from.last_name || '';
    isPremium = message.from.is_premium || false;
    languageCode = message.from.language_code || 'en';
  }

  searchText = message.text || '';
}

// ✅ Берем business_connection_id из business_message
if (body.business_message) {
  businessConnectionId = body.business_message.business_connection_id;
}

// Убираем префиксы "Music" или "Музыка"
if (searchText) {
  searchText = searchText.replace(/^(music|музыка)\s+/i, '');
}

return [{
  json: {
    chat_id: chatId,
    message_id: messageId,
    username: username,
    first_name: firstName,
    last_name: lastName,
    is_premium: isPremium,
    language_code: languageCode,
    search_text: searchText,
    business_connection_id: businessConnectionId
  }
}];

const deezerData = $input.first().json;
const tracks = deezerData.data;
const total = deezerData.total;
const parsedData = $('Parse search command').first().json;

if (!tracks || tracks.length === 0) {
  return [{
    json: {
      chat_id: parsedData.chat_id,
      reply_to_message_id: parsedData.message_id,
      text: `❌ Nothing found: <b>${parsedData.search_text}</b>\n\n💡 Try:\n• Artist name only\n• Song title only\n• Different spelling`,
      parse_mode: 'HTML'
    }
  }];
}

const chatId = parsedData.chat_id;
const replyToMessageId = parsedData.message_id;
const query = parsedData.search_text;
const offset = 0;

const photo = tracks[0]?.album?.cover_big
  || tracks[0]?.album?.cover_medium
  || '';

const displayTracks = tracks.slice(0, 10);

const inline_keyboard = displayTracks.map(track => ([
  {
    text: `🎵 ${track.title} — ${track.artist.name}`,
    callback_data: `dz|${track.id}`
  }
]));

if (offset + 10 < total) {
  inline_keyboard.push([
    {
      text: `More… (${offset + 10}/${total})`,
      callback_data: `dzmore|${query}|${offset + 10}`
    }
  ]);
}

return [{
  json: {
    chat_id: chatId,
    reply_to_message_id: replyToMessageId,
    photo: photo,
    caption: `🔍 Search results for: <b>${query}</b>`,
    parse_mode: 'HTML',
    reply_markup: { inline_keyboard }
  }
}];

const searchText = $('Parse search command').first().json.search_text || '';
const cleanQuery = searchText
  .replace(/[^\w\s\u0400-\u04FF-]/gi, ' ')
  .replace(/\s+/g, ' ')
  .trim();

return [{
  json: {
    search_query: encodeURIComponent(cleanQuery)
  }
}];
